#!/usr/bin/env bash
# ============================================================================
# simpsons_paradox - Database Initialization Script
# ============================================================================
# Generated by rulebook-to-postgres tool.
#
# Two responsibilities: install magic-links auth, then run all
# NN[b]?-*.sql files in lex order. Skips *.sql.disabled.
#
# Local dev loop: re-run after `effortless build` to apply generated SQL.
# Re-running against a populated DB should be safe — every file is meant
# to be idempotent. If it isn't, fix the file, not this script.
# ============================================================================

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
DEFAULT_CONN="postgresql://postgres@localhost:5432/simpsons_paradox"
DATABASE_URL="${DATABASE_URL:-${1:-$DEFAULT_CONN}}"

# ----------------------------------------------------------------------
# Refuse hosted bases URLs — init-db.sh drops and recreates everything.
# Point DATABASE_URL at local Postgres only (default: simpsons_paradox).
# ----------------------------------------------------------------------
if echo "$DATABASE_URL" | grep -qi 'bases\.effortlessapi\.com' ; then
    echo "refusing to run init-db.sh against bases.effortlessapi.com" >&2
    echo "init-db.sh is for local dev only — it drops and recreates all tables" >&2
    echo "use the default: postgresql://postgres@localhost:5432/simpsons_paradox" >&2
    exit 2
fi
if [ -n "${BASES_DATABASE_URL:-}" ] && [ "$DATABASE_URL" = "$BASES_DATABASE_URL" ]; then
    echo "refusing to run init-db.sh: DATABASE_URL == BASES_DATABASE_URL" >&2
    echo "init-db.sh is for local dev only — it drops and recreates all tables" >&2
    exit 2
fi

echo "[init-db] target: $DATABASE_URL"

# ----------------------------------------------------------------------
# 1. Always (re-)install magic-links auth. Idempotent → safe to repeat.
# ----------------------------------------------------------------------
if [ -f "${SCRIPT_DIR}/install-magic-links.sql" ]; then
    echo "[init-db] [RUN]  install-magic-links.sql"
    psql "$DATABASE_URL" -v ON_ERROR_STOP=1 -f "${SCRIPT_DIR}/install-magic-links.sql"
else
    echo "[init-db] note: install-magic-links.sql not present — skipping auth install"
    echo "[init-db]       fetch from https://magiclink.effortlessapi.com/install-magic-links/v1.sql"
fi

# ----------------------------------------------------------------------
# 2. Run all NN[b]?-*.sql files in lex order. Skip *.sql.disabled.
# ----------------------------------------------------------------------
shopt -s nullglob
FILES_RUN=()
FILES_SKIP=()
for f in "${SCRIPT_DIR}"/[0-9][0-9]*-*.sql "${SCRIPT_DIR}"/[0-9][0-9]*-*.sql.disabled; do
    [ -f "$f" ] || continue
    base=$(basename "$f")
    if [[ "$base" == *.disabled ]]; then
        echo "[init-db] [SKIP] $base"
        FILES_SKIP+=("$base")
        continue
    fi
    # 99-fk-constraints.sql — FK enforcement is opt-in. Demos must never
    # fail on FK violations; the rulebook still documents the relationships
    # and 01-drop-and-create-tables.sql installs the FK indexes inline.
    if [[ "$base" == "99-fk-constraints.sql" && "${EFFORTLESS_ENFORCE_FKS:-false}" != "true" ]]; then
        echo "[init-db] [SKIP] $base (set EFFORTLESS_ENFORCE_FKS=true to apply FK constraints)"
        FILES_SKIP+=("$base")
        continue
    fi
    echo "[init-db] [RUN]  $base"
    if [[ "$base" == *b-* ]]; then
        # customize files (NNb-*) tolerate per-row errors
        psql "$DATABASE_URL" -f "$f"
    elif [[ "$base" == "05-insert-data.sql" ]]; then
        psql "$DATABASE_URL" -v ON_ERROR_STOP=1 -f "$f"
    else
        psql "$DATABASE_URL" -v ON_ERROR_STOP=1 -f "$f"
    fi
    FILES_RUN+=("$base")
done

# ----------------------------------------------------------------------
# 3. function-overrides/*.sql (per-function tweaks; errors non-fatal).
#    Two-pass: non-policy files first, then policy__* files (policies
#    often reference custom functions).
# ----------------------------------------------------------------------
run_override() {
    local sql_file="$1"
    local base; base=$(basename "$sql_file")
    if [[ "$base" == *.disabled ]]; then
        echo "[init-db] [SKIP] function-overrides/$base"
        return 0
    fi
    echo "[init-db] [RUN]  function-overrides/$base"
    psql "$DATABASE_URL" -f "$sql_file" || echo "[init-db] [WARN] $base failed (non-fatal)"
}
if compgen -G "${SCRIPT_DIR}/function-overrides/*.sql" > /dev/null 2>&1; then
    for sql_file in "${SCRIPT_DIR}/function-overrides/"*.sql; do
        base=$(basename "$sql_file")
        [[ "$base" == policy__* ]] && continue
        run_override "$sql_file"
    done
    for sql_file in "${SCRIPT_DIR}/function-overrides/"policy__*.sql; do
        [[ -f "$sql_file" ]] || continue
        run_override "$sql_file"
    done
fi

# ----------------------------------------------------------------------
# 4. Write .applied-manifest.json (compare to .build-manifest.json for drift).
# ----------------------------------------------------------------------
APPLIED_AT="$(date -u +%Y-%m-%dT%H:%M:%SZ)"
MANIFEST="${SCRIPT_DIR}/.applied-manifest.json"
{
    printf '{\n'
    printf '  "applied_at": "%s",\n' "$APPLIED_AT"
    printf '  "target": "%s",\n' "$DATABASE_URL"
    printf '  "files_run": ['
    sep=''
    for f in "${FILES_RUN[@]:-}"; do
        [ -z "$f" ] && continue
        printf '%s"%s"' "$sep" "$f"
        sep=','
    done
    printf '],\n'
    printf '  "files_skipped": ['
    sep=''
    for f in "${FILES_SKIP[@]:-}"; do
        [ -z "$f" ] && continue
        printf '%s"%s"' "$sep" "$f"
        sep=','
    done
    printf ']\n'
    printf '}\n'
} > "$MANIFEST"

echo "[init-db] complete (manifest: .applied-manifest.json)"

# ----------------------------------------------------------------------
# 5. Export hydrated rulebook — computed view values checked into git.
# ----------------------------------------------------------------------
if [ -f "${SCRIPT_DIR}/export-hydrated-rulebook.sh" ]; then
    DATABASE_URL="$DATABASE_URL" bash "${SCRIPT_DIR}/export-hydrated-rulebook.sh"
fi

# ----------------------------------------------------------------------
# 6. Corpus summary PDF — conclusions + findings from live views.
# ----------------------------------------------------------------------
if [ -f "${SCRIPT_DIR}/generate-summary-pdf.sh" ]; then
    DATABASE_URL="$DATABASE_URL" bash "${SCRIPT_DIR}/generate-summary-pdf.sh"
fi

# ----------------------------------------------------------------------
# 6b. Corpus details PDF — expanded companion with full hypothesis detail.
# ----------------------------------------------------------------------
if [ -f "${SCRIPT_DIR}/generate-details-pdf.sh" ]; then
    DATABASE_URL="$DATABASE_URL" bash "${SCRIPT_DIR}/generate-details-pdf.sh"
fi
